import fs from "node:fs";
import path from "node:path";
import {
  LlamaCloudIndex,
  SimpleDirectoryReader,
} from "llamaindex";

async function main() {
  try {
    // 1. Read trial_id
    const trialIdPath = "/logs/artifacts/trial_id";
    const trialId = fs.readFileSync(trialIdPath, "utf-8").trim();
    const indexName = `harbor-ts-index-${trialId}`;
    console.log(`Index name: ${indexName}`);

    // 2. Load documents
    const dataDir = "/home/user/myproject/data";
    const reader = new SimpleDirectoryReader();
    const documents = await reader.loadData({ directoryPath: dataDir });
    console.log(`Loaded ${documents.length} documents.`);

    // 3. Create LlamaCloud managed index
    console.log("Creating LlamaCloud index...");
    const index = await LlamaCloudIndex.fromDocuments({
      documents,
      name: indexName,
      projectName: "Default",
    });

    // 4. Build query engine and query
    const query = "What is the capital of France?";
    console.log(`Query: ${query}`);
    const queryEngine = index.asQueryEngine();
    const response = await queryEngine.query({ query });
    const answer = response.toString();
    console.log(`Answer: ${answer}`);

    // 5. Write to output.log
    const outputPath = "/home/user/myproject/output.log";
    const outputLines = [
      `Index name: ${indexName}`,
      `Query: ${query}`,
      `Answer: ${answer}`,
      `Summary: ${JSON.stringify({
        index_name: indexName,
        num_documents: documents.length,
      })}`,
    ];

    fs.writeFileSync(outputPath, outputLines.join("\n") + "\n");
    console.log(`Results written to ${outputPath}`);
  } catch (error) {
    console.error("Error:", error);
    process.exit(1);
  }
}

main();

